function safeErrorCode(status,message){ const m=String(message||"").toLowerCase(); if(status===401) return "session_missing"; if(status===403 && m.includes("csrf")) return "csrf_failed"; if(status===403 && m.includes("origin")) return "origin_rejected"; if(status===403) return "unauthorized"; if(status===409) return "duplicate_cohort"; if(m.includes("start date")) return "invalid_start_date"; if(m.includes("capacity")) return "invalid_capacity"; if(m.includes("cohort_name")) return "missing_cohort_name"; return status>=500?"cohort_persistence_failed":"invalid_request"; }
function safeErrorMessage(status,message){ if(status===401) return message || "We could not sign you in with those details."; if(status===403 && String(message||"").toLowerCase().includes("csrf")) return "The secure form expired. Reload and try again."; if(status===403 && String(message||"").toLowerCase().includes("origin")) return "The request origin is not trusted. Reload this page and try again."; if(status===403) return message || "You do not have permission to complete this request."; if(status===409) return message || "The request conflicts with existing data."; return message || "The cohort could not be saved."; }
function asyncRoute(fn){return (req,res)=>fn(req,res).catch(e=>{const status=e.status||500;const code=e.code||safeErrorCode(status,e.message);const requestId=e.request_id||`lwc_${Date.now().toString(36)}`;res.status(status).type("application/json").json({ok:false,error:code,message:status>=500?(e.message||"The cohort could not be saved."):safeErrorMessage(status,e.message),stage:e.stage||"request",request_id:requestId,rolled_back:e.rolled_back===true});});}
function asyncHtml(fn){return (req,res)=>fn(req,res).catch(e=>{const status=e.status||500; if(status===401) return res.redirect(302, `/the-leader-within/facilitator/sign-in`); const title=status===403?"Leader Within Access Needed":"The Leader Within is unavailable"; const message=status===403?"Your account is signed in, but it has not been assigned to a Leader Within facilitator role or cohort.":"We could not open this Leader Within page right now."; const actions=status===403?`<p><a class="btn" href="/the-leader-within.html">Return to The Leader Within</a> <a class="btn secondary" href="mailto:program-admin@example.com?subject=Leader%20Within%20facilitator%20access">Contact a Program Administrator</a></p>${signOutForms()}`:`<p><a class="btn" href="/the-leader-within.html">Return to The Leader Within</a></p>`; res.status(status).type("html").send(html(title, `<h1>${title}</h1><p>${message}</p>${actions}`));});}
function html(title, body){return `<!doctype html><html><head><meta name="viewport" content="width=device-width, initial-scale=1"><title>${title}</title><link rel="stylesheet" href="/the-leader-within/programs/program.css"></head><body><main class="section">${body}</main></body></html>`;}
function parseCookieHeader(rawCookie=""){return String(rawCookie||"").split(";").map(p=>p.trim()).filter(Boolean).reduce((acc,p)=>{const idx=p.indexOf("="); if(idx<0) return acc; acc[p.slice(0,idx)]=decodeURIComponent(p.slice(idx+1)||""); return acc;},{});}
