function signOutForms(){return `<form class="card" data-tlw-signout="leader-within"><button class="btn secondary" type="submit">Sign Out of Leader Within</button><p role="status"></p></form><form class="card" data-tlw-signout="complete"><button class="btn secondary" type="submit">Sign Out Completely</button><p role="status"></p></form><script>${signOutScript()}</script>`;}
function requireAddParticipantFormActor(req){ const a=svc.canonicalLeaderWithinActor(svc.trustedActorFromRequest(req)); const role=String(a?.facilitator_role||a?.role||"").trim().toLowerCase(); if(!a?.authenticated) { const e=new Error("Facilitator session required."); e.status=401; throw e; } if(!(svc.canAdministerLeaderWithin(a)||["facilitator","lead_facilitator","coach","staff"].includes(role))) { const e=new Error("Facilitator role required."); e.status=403; throw e; } return a; }

