function cookieOptionsForCsrf(req){ const secure=!!(req.secure||String(req.headers["x-forwarded-proto"]||"").toLowerCase()==="https"||process.env.NODE_ENV==="production"); return `Path=/; SameSite=${secure?"None":"Lax"}${secure?"; Secure":""}; HttpOnly; Max-Age=900`; }
function clearFirstLoginCsrfCookies(req){ const secure=!!(req.secure||String(req.headers["x-forwarded-proto"]||"").toLowerCase()==="https"||process.env.NODE_ENV==="production"); const suffix=`SameSite=${secure?"None":"Lax"}${secure?"; Secure":""}; HttpOnly; Max-Age=0`; return ["/","/api","/api/the-leader-within","/the-leader-within","/the-leader-within/first-login"].map(path=>`${FIRST_LOGIN_CSRF_COOKIE}=; Path=${path}; ${suffix}`); }
