function firstLoginCsrfDiagnostics(req,supplied,expected){ const values=cookieValues(req,FIRST_LOGIN_CSRF_COOKIE); const headerPresent=!!supplied; const cookiePresent=values.length>0; const tokenFormatValid=!supplied || /^[A-Fa-f0-9]{64}$/.test(supplied); let reason="csrf_token_mismatch"; if(values.length>1) reason="duplicate_csrf_cookie"; else if(!headerPresent) reason="csrf_header_missing"; else if(!cookiePresent) reason="csrf_binding_cookie_missing"; else if(!tokenFormatValid) reason="csrf_token_format_invalid"; else if(!expected) reason="csrf_context_missing"; else if(supplied!==expected) reason="csrf_token_mismatch"; return { csrf_header_present:headerPresent, csrf_binding_cookie_present:cookiePresent, csrf_binding_cookie_occurrence_count:values.length, csrf_context_found:values.length===1, csrf_context_expired:false, csrf_context_consumed:false, csrf_token_format_valid:tokenFormatValid, csrf_token_match:!!expected && supplied===expected && values.length===1, csrf_validator_count:1, route_classification:isFirstLoginExchange(req)?"public_youth_credential_exchange":undefined, exact_safe_denial_reason:reason, request_id:requestId(req), deployed_commit:BUILD_COMMIT, handler_version:FIRST_LOGIN_CSRF_HANDLER_VERSION } }
function requireCsrf(req,res,next){ if(!csrfProtected(req)) return next(); req.tlwCsrfValidatorCount=(req.tlwCsrfValidatorCount||0)+1; const supplied=String(req.headers["x-csrf-token"]||""); const expected=isFirstLoginExchange(req) ? (firstLoginCsrfCookie(req) || req.headers["x-leader-within-csrf-test-token"]) : (req.leaderWithinYouthActor?.csrf_token || req.leaderWithinFacilitatorActor?.csrf_token || req.headers["x-leader-within-csrf-test-token"]); const firstLoginDiagnostics=isFirstLoginExchange(req)?firstLoginCsrfDiagnostics(req,supplied,expected):null; const ok=firstLoginDiagnostics ? firstLoginDiagnostics.csrf_token_match : (!!expected && supplied===expected); if(!ok) { res.status(403).setHeader("Content-Type","application/json"); return res.json({ok:false,error:"csrf_failed",message:"The secure form expired. Reload and try again.",stage:"csrf_validation",request_id:requestId(req),rolled_back:false,route_classification:isFirstLoginExchange(req)?"public_youth_credential_exchange":undefined,...(firstLoginDiagnostics||{})}); } next(); }
