 r.get('/the-leader-within/sign-in', (req,res)=>res.type('html').send(html('Welcome to The Leader Within', `<h1>Welcome to The Leader Within</h1><p>Enter your Leader ID and private sign-in code.</p><p>Your facilitator must add you to the program before you can sign in.</p><form id="youthSignInForm"><label>Leader ID <input name="leader_id" autocomplete="username"></label><label>Private sign-in code <input name="secret" type="password" autocomplete="current-password"></label><button class="btn" id="youthSignInButton">Start or Continue My Journey</button><p id="youthSignInStatus" role="alert"></p></form><section class="card"><h2>Help Signing In</h2><ul><li>Ask your facilitator to confirm your Leader ID.</li><li>Ask your facilitator to reset your temporary sign-in code.</li><li>Do not share your private code with other participants.</li></ul></section><script>document.getElementById("youthSignInForm").addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget,b=document.getElementById("youthSignInButton"),s=document.getElementById("youthSignInStatus");b.disabled=true;s.textContent="";try{const r=await fetch("/api/the-leader-within/auth/sign-in",{method:"POST",headers:{"Content-Type":"application/json"},credentials:"include",body:JSON.stringify(Object.fromEntries(new FormData(f).entries()))});const d=await r.json().catch(()=>({}));if(!r.ok) throw new Error(d.error||"We could not sign you in with those details.");window.location.href=d.route||"/the-leader-within/my-program";}catch(err){s.textContent=err.message||"We could not sign you in with those details.";b.disabled=false;}});</script>`)));
