 r.post('/api/the-leader-within/facilitator/sign-out-completely', requireFacilitatorCsrf, asyncRoute(async(req,res)=>{ await svc.revokeFacilitatorSession(pool,req); await svc.revokeYouthSession(pool,req); const cookies=parseCookieHeader(req.headers.cookie||''); const token=String(cookies[OWNER_SESSION_COOKIE]||'').trim(); if(token) await pool.query('DELETE FROM auth_sessions WHERE token_hash = $1',[sha256(token)]); res.setHeader('Set-Cookie',[...svc.clearAllLeaderWithinFacilitatorCookies(req),...svc.clearAllYouthCookies(req),buildOwnerSessionCookie(req,'',0)]); res.json({ok:true,redirect:'/the-leader-within/facilitator/signed-out?complete=1'}); }));
