 r.get('/the-leader-within/first-login', (req,res)=>res.type('html').send(html('Create Private Sign-In Code', `<h1>Create Private Sign-In Code</h1><p>Use your Leader ID and temporary credential one time, then create a private code.</p><form id="firstLoginForm"><label>Leader ID <input name="leader_id" required autocomplete="username"></label><label>Temporary password/PIN <input name="temporary_secret" type="password" required autocomplete="one-time-code"></label><label>New private password/PIN <input name="new_secret" type="password" required minlength="6" autocomplete="new-password"></label><label>Confirm private password/PIN <input name="confirm_secret" type="password" required minlength="6" autocomplete="new-password"></label><button class="btn" id="firstLoginButton" disabled>Preparing secure form…</button><p id="firstLoginStatus" role="alert"></p></form><script>let firstLoginCsrf="";const firstLoginMessages={csrf_failed:"The secure form expired. Reload and try again.",invalid_temporary_credential:"The Leader ID or temporary credential is incorrect.",temporary_credential_used:"This temporary credential has already been used. Ask your facilitator for a reset.",account_temporarily_locked:"Too many attempts were made. Try again later or ask your facilitator for help.",credential_mismatch:"The new private codes do not match.",weak_private_credential:"Choose a stronger private code."};const firstLoginButton=document.getElementById("firstLoginButton"),firstLoginStatus=document.getElementById("firstLoginStatus");fetch("/api/the-leader-within/auth/first-login/csrf",{credentials:"include"}).then(r=>r.json()).then(d=>{firstLoginCsrf=d.csrf_token||"";if(!firstLoginCsrf)throw new Error();firstLoginButton.disabled=false;firstLoginButton.textContent="Create Private Code";}).catch(()=>{firstLoginStatus.textContent=firstLoginMessages.csrf_failed;});async function refreshFirstLoginCsrf(){firstLoginButton.disabled=true;const r=await fetch("/api/the-leader-within/auth/first-login/csrf",{credentials:"include"});const d=await r.json();firstLoginCsrf=d.csrf_token||"";if(!firstLoginCsrf)throw new Error();firstLoginButton.disabled=false;}document.getElementById("firstLoginForm").addEventListener("submit",async(e)=>{e.preventDefault();const b=firstLoginButton,s=firstLoginStatus;if(b.dataset.submitting==="1")return;if(!firstLoginCsrf){s.textContent=firstLoginMessages.csrf_failed;return;}b.dataset.submitting="1";b.disabled=true;s.textContent="";try{const r=await fetch("/api/the-leader-within/auth/first-login",{method:"POST",headers:{"Content-Type":"application/json","x-csrf-token":firstLoginCsrf},credentials:"include",body:JSON.stringify(Object.fromEntries(new FormData(e.currentTarget).entries()))});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.message||firstLoginMessages[d.error]||"We could not create your private code.");location.href=d.redirect_to||d.route||"/the-leader-within/my-program";}catch(err){s.textContent=err.message||"We could not create your private code.";try{await refreshFirstLoginCsrf();}catch(_){}b.disabled=false;b.dataset.submitting="0";}});</script>`)));
