 r.get('/the-leader-within/stories', asyncRoute(async(req,res)=>{ const state=await svc.listWeeklyStories(pool,req); res.type('html').send(html('This Week\'s Stories', `<h1>This Week's Stories</h1><p>Week ${state.position.week_number} • Session ${esc(state.position.session_key)}</p><section class="grid">${state.weekly_stories.map(st=>`<article class="card"><p class="chip">${st.status==='current'?'Featured story':'Weekly library'}</p><h2>${esc(st.title)}</h2><p>${esc(st.short_summary)}</p><p>${esc(st.leadership_behavior)} • ${st.estimated_minutes} min • ${esc(st.completed?'Completed':'Not complete')}</p><a class="btn" href="${esc(st.read_url)}">Read</a></article>`).join('')}</section><p><a class="btn secondary" href="/the-leader-within/my-program">Return to mission</a></p>`)); }));
