 r.get('/the-leader-within/stories/:storyId', asyncRoute(async(req,res)=>{ const data=await svc.getAssignedStory(pool,req,req.params.storyId); const st=data.story; res.type('html').send(html(st.title, `<h1>${esc(st.title)}</h1><p><strong>Leadership focus:</strong> ${esc(st.leadership_behavior)}</p><section class="card"><h2>Story</h2><p>${esc(st.full_story)}</p></section><section class="card"><h2>Listen</h2><p>${st.listen_url?`<audio controls src="${esc(st.listen_url)}"></audio>`:'<button class="btn secondary" type="button" aria-disabled="true" disabled>Audio coming soon</button>'}</p></section><section class="card"><h2>What to notice</h2><ul>${(st.what_to_notice||[]).map(x=>`<li>${esc(x)}</li>`).join('')}</ul><p><strong>Reflection question:</strong> ${esc(st.reflection_question)}</p></section><form id="storyCompleteForm"><button class="btn" type="submit">Mark Story Complete</button><p role="status"></p></form><script>const csrf=${JSON.stringify(data.state.csrf_token||req.leaderWithinYouthActor?.csrf_token||'')};document.getElementById('storyCompleteForm').addEventListener('submit',async e=>{e.preventDefault();const s=e.currentTarget.querySelector('[role=status]');s.textContent='Saving…';const r=await fetch('/api/the-leader-within/stories/${encodeURIComponent(st.id)}/complete',{method:'POST',headers:{'Content-Type':'application/json','x-csrf-token':csrf},credentials:'include',body:'{}'});s.textContent=r.ok?'Story completed. Return to your mission to see progress.':'Could not complete story.';});</script><p><a class="btn secondary" href="/the-leader-within/my-program">Return to mission</a> <a class="btn secondary" href="/the-leader-within/stories">This week's stories</a></p>`)); }));

 r.get('/the-leader-within/archetypes', (_req,res)=>{ const cards=svc.archetypeCards().map(a=>`<article class="card archetype-card" data-archetype="${esc(a.identity)}"><div class="archetype-symbol" role="img" aria-label="${esc(a.alt)}">${a.symbol}</div><h2>${esc(a.identity)}</h2><p><strong>${esc(a.official)}</strong></p><p><strong>Identity phrase:</strong> ${esc(a.phrase)}</p><p>${esc(a.phrase)} No archetype is better than another, no archetype is a permanent label, and strong leaders learn to use more than one style.</p><h3>Natural strengths</h3><ul>${a.strengths.map(x=>`<li>${esc(x)}</li>`).join('')}</ul><p><strong>Common growth area:</strong> ${esc(a.growth)}</p><p><strong>Real-life example:</strong> ${esc(a.example)}</p><p><strong>Example leadership practice:</strong> ${esc(a.practice)}</p><p><strong>Related story example:</strong> ${esc(a.story)}</p><p><strong>How this may show up in you:</strong> ${esc(a.shows)}</p></article>`).join(''); res.type('html').send(html('Leader Within Archetypes', `<style>.archetype-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:1rem}.archetype-symbol{font-size:3.5rem}.card{max-width:70ch}.hero{max-width:75ch}.btn{min-height:44px}@media(max-width:720px){.archetype-grid{grid-template-columns:1fr}.card{max-width:100%}}</style><section class="hero"><h1>Discover the Ways Leadership Can Show Up</h1><p>You may use more than one leadership style. The assessment helps you notice which strengths appear most naturally right now.</p></section><section class="archetype-grid">${cards}</section><section class="card"><h2>How the styles work together</h2><p>The Compass helps name direction, The Builder makes follow-through possible, The Bridge keeps people connected, The Spark brings ideas and expression, and The Pathfinder helps the group take responsible action.</p></section><p><a class="btn" href="/the-leader-within/assessment">Take the Leadership Assessment</a> <a class="btn secondary" href="/the-leader-within/my-program">Return to Today’s Mission</a></p>`)); });
 r.get('/api/the-leader-within/assessment', asyncRoute(async(req,res)=>res.json(await svc.getAssessmentEntry(pool,req))));
 r.get('/the-leader-within/assessment', asyncRoute(async(req,res)=>{ const d=await svc.getAssessmentEntry(pool,req); const qs=d.questions.map((q,i)=>`<fieldset class="card question" data-question-id="${esc(q.question_id)}"><legend>${i+1}. ${esc(q.prompt)}</legend>${q.options.map(o=>`<label><input type="radio" name="${esc(q.question_id)}" value="${esc(o.option_id)}" required> ${esc(o.text)}</label>`).join('')}</fieldset>`).join(''); res.type('html').send(html('Leadership Assessment', `<style>.question label{display:block;margin:.5rem 0}.progress{font-weight:700}.btn,button{min-height:44px}@media(max-width:720px){.card{max-width:100%}}</style><h1>Start Assessment</h1><section class="card"><h2>Discover Your Leadership Style</h2><p>Question count: ${d.question_count}. Estimated time: ${d.estimated_minutes} minutes.</p><p>There are no good or bad results. Answer based on what you usually do right now. Results are a guide, not a permanent label.</p><p class="progress">Assessment state: ${esc(d.state.state)} • ${d.state.progress.answered}/${d.state.progress.total} answered</p><p><a href="/the-leader-within/archetypes">Learn About the Archetypes</a> • <a href="/the-leader-within/my-program">Return to mission</a></p></section><form id="assessmentForm">${qs}<button class="btn" type="button" id="saveBtn">Save progress</button> <button class="btn" type="submit">Complete assessment</button><p role="status"></p></form><script>const csrf=${JSON.stringify(d.csrf_token||'')};function answers(){const out={};document.querySelectorAll('.question').forEach(q=>{const id=q.dataset.questionId;const checked=q.querySelector('input:checked');if(checked)out[id]=checked.value;});return out;}async function post(url){const r=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json','x-csrf-token':csrf},credentials:'include',body:JSON.stringify({answers:answers()})});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(data.message||data.error||'Could not save assessment.');return data;}document.getElementById('saveBtn').onclick=async()=>{const s=document.querySelector('[role=status]');s.textContent='Saving…';try{await post('/api/the-leader-within/assessment/progress');s.textContent='Progress saved.';}catch(e){s.textContent=e.message;}};document.getElementById('assessmentForm').onsubmit=async e=>{e.preventDefault();const s=e.currentTarget.querySelector('[role=status]');s.textContent='Completing…';try{const d=await post('/api/the-leader-within/assessment/complete');location.href=d.redirect_to||'/the-leader-within/assessment/results';}catch(err){s.textContent=err.message;}};</script>`)); }));
