 r.get('/the-leader-within/assessment/results', asyncRoute(async(req,res)=>{ const d=await svc.getAssessmentResult(pool,req); res.type('html').send(html('Your Leadership Profile', `<h1>Your Leadership Profile</h1><section class="card"><div role="img" aria-label="${esc(d.primary.alt)}" style="font-size:4rem">${d.primary.symbol}</div><h2>Primary archetype: ${esc(d.primary.identity)}</h2><p><strong>${esc(d.primary.official)}</strong></p><p>${esc(d.primary.phrase)}</p><h3>Natural strengths</h3><ul>${d.primary.strengths.map(x=>`<li>${esc(x)}</li>`).join('')}</ul><p><strong>Growth opportunity:</strong> ${esc(d.primary.growth)}</p><p><strong>How you can use this today:</strong> ${esc(d.primary.practice)}</p></section><section class="card"><h2>Secondary strength: ${esc(d.secondary.identity)}</h2><p><strong>${esc(d.secondary.official)}</strong> — ${esc(d.secondary.phrase)}</p></section><section class="card"><h2>Suggested leadership practice</h2><p>${esc(d.suggested_practice.title)}</p><form id="practiceAccept"><button class="btn">Accept this practice into Today’s Leadership Mission</button><p role="status"></p></form></section><p>Results are not a permanent label. Strong leaders learn to use more than one style.</p><p><a class="btn secondary" href="/the-leader-within/archetypes">View all archetypes</a> <a class="btn secondary" href="/the-leader-within/my-program">Return to Today’s Mission</a></p><script>const csrf=${JSON.stringify(req.leaderWithinYouthActor?.csrf_token||'')};document.getElementById('practiceAccept').onsubmit=async e=>{e.preventDefault();const s=e.currentTarget.querySelector('[role=status]');s.textContent='Saving…';const r=await fetch('/api/the-leader-within/assessment/suggested-practice',{method:'POST',headers:{'Content-Type':'application/json','x-csrf-token':csrf},credentials:'include',body:'{}'});s.textContent=r.ok?'Practice selected.':'Could not select practice.';};</script>`)); }));
