 r.get('/the-leader-within/facilitator/dashboard', asyncHtml(async(req,res)=>{const d=await svc.facilitatorDashboard(pool,req);res.type('html').send(html('Leader Within Facilitator Dashboard', `<h1>Leader Within Facilitator Dashboard</h1><p>Facilitator: ${d.facilitator?.display_name||d.facilitator?.email||'Signed-in facilitator'}</p>${d.facilitator?.canonical_email?`<p>Admin account: ${d.facilitator.canonical_email}</p>`:""}<p>Organization: ${d.facilitator?.tenant_slug||'Assigned tenant'}</p>${d.cohorts.length===0?`<section class="card"><h2>No Leader Within cohorts are currently assigned to you.</h2><p>${d.empty_state.message}</p>${d.empty_state.can_create_cohort?`<a class="btn" href="/admin/the-leader-within/bootstrap">Create Your First Leader Within Cohort</a>`:`<p>Contact a program administrator to receive a cohort assignment.</p>`}</section>`:``}<section class="grid"><article class="card">Active cohorts: ${d.metrics.active_cohorts}</article><article class="card">Active participants: ${d.metrics.active_participants}</article><article class="card">Current week/session: ${d.metrics.current_week}A</article><article class="card">Reflections awaiting review: ${d.metrics.reflections_awaiting_review}</article><article class="card">Follow-up flags: ${d.metrics.follow_up_flags}</article></section>${d.cohorts.map(c=>`<section class="card"><h2>${c.name}</h2><p>${c.participant_count} participants • Week ${c.current_week} Session ${c.current_session}</p><a class="btn" href="/admin/the-leader-within/cohorts/${c.id}">Open Cohort</a> <a class="btn secondary" href="/admin/the-leader-within/cohorts/${c.id}/add-participant">Add Participant</a></section>`).join('')}<section class="card"><h2>Today’s facilitator plan</h2><p>${d.plan.session_title}</p><p>${d.plan.learning_objective}</p></section>${signOutForms()}`));}));
