 r.get('/admin/the-leader-within/cohorts/:cohortId', asyncHtml(async(req,res)=>{const d=await svc.facilitatorCohortDetail(pool,req); const c=d.cohort; const rows=d.participants.map(p=>`<tr><td>${esc(p.participant.preferred_name)}</td><td>${esc(p.participant.enrollment_status)}</td><td>${esc(p.assessment.status)}</td><td>${esc(p.stories.featured_story.title)}</td><td>${p.stories.completed_count}/${p.stories.assigned_count}</td><td>${esc(p.practice.status)}</td><td>${esc(p.movement.status)}</td><td>${esc(p.reflection.review_status)}</td><td>${p.mission.percent_complete}%</td><td>${p.support.follow_up_flag?'Open':'None'}</td><td><a href="/admin/the-leader-within/participants/${p.participant.id}">Open</a></td></tr>`).join(''); const cards=d.participants.map(p=>`<article class="card progress-card"><h3>${esc(p.participant.preferred_name)}</h3><p>Assessment: ${esc(p.assessment.status)}</p><p>Story: ${esc(p.stories.featured_story.title)} (${p.stories.completed_count}/${p.stories.assigned_count})</p><p>Practice: ${esc(p.practice.status)} • Movement: ${esc(p.movement.status)}</p><p>Reflection: ${esc(p.reflection.review_status)}</p><p>Weekly progress: ${p.mission.percent_complete}%</p><p>Follow-up: ${p.support.follow_up_flag?'Open':'None'}</p><p><a class="btn" href="/admin/the-leader-within/participants/${p.participant.id}">Open Participant</a></p></article>`).join(''); res.type('html').send(html(c.name, `<style>@media(max-width:720px){.progress-table{display:none}.progress-cards{display:grid}.btn,button{min-height:44px}}@media(min-width:721px){.progress-cards{display:none}}</style><h1>${esc(c.name)}</h1><p>${esc(c.program_title)} • ${esc(c.curriculum_version||'2026.07')} • Week ${esc(d.position.week_number)} Session ${esc(d.position.session_key)} • Status ${esc(c.status||'active')}</p><p><a class="btn" href="/admin/the-leader-within/cohorts/${c.id}/add-participant">Add Participant</a> <a class="btn secondary" href="/the-leader-within/facilitator/dashboard">Return to Dashboard</a></p><section class="grid"><article class="card">Average progress: ${d.outcomes.average_participant_progress}%</article><article class="card">Reflection submissions: ${d.outcomes.reflection_submission_rate}%</article><article class="card">Assessment completion: ${d.outcomes.assessment_completion_rate}%</article><article class="card">Open flags: ${d.outcomes.follow_up_flags_opened-d.outcomes.follow_up_flags_resolved}</article></section><section class="card"><h2>Session Advancement Controls</h2><p>Current pathway: ${esc(c.program_title)} • Version ${esc(c.curriculum_version||'2026.07')} • Current Week ${esc(d.position.week_number)} Session ${esc(d.position.session_key)}</p><p>Next valid session is resolved server-side before mutation. Review incomplete missions and reflections awaiting review before advancing.</p><button class="btn" data-action-url="/api/admin/the-leader-within/cohorts/${c.id}/advance-session">Advance Session</button> <button class="btn secondary" data-action-url="/api/admin/the-leader-within/cohorts/${c.id}/advance-week">Advance Week</button> <button class="btn secondary" data-action-url="/api/admin/the-leader-within/cohorts/${c.id}/pause">Pause Cohort</button> <button class="btn secondary" data-action-url="/api/admin/the-leader-within/cohorts/${c.id}/resume">Resume Cohort</button> <button class="btn secondary" data-action-url="/api/admin/the-leader-within/cohorts/${c.id}/reopen-session">Reopen Session</button><p role="status"></p></section><section class="card"><h2>Activity Feed</h2><p>Safe activity events are available through audit records; summaries omit private notes, credential data, sessions, and full reflection text.</p></section><section class="card"><h2>Cohort Progress Table</h2><table class="progress-table"><thead><tr><th>Participant</th><th>Enrollment</th><th>Assessment</th><th>Current story</th><th>Story completed</th><th>Practice</th><th>Movement</th><th>Reflection reviewed</th><th>Weekly progress</th><th>Follow-up</th><th>Actions</th></tr></thead><tbody>${rows}</tbody></table><div class="progress-cards">${cards}</div></section>`));}));
 r.get('/admin/the-leader-within/cohorts/:cohortId/add-participant', asyncHtml(async(req,res)=>{res.setHeader('X-TLW-Handler-Version', ADD_PARTICIPANT_GET_HANDLER_VERSION); requireAddParticipantFormActor(req); const d=await svc.facilitatorDashboard(pool,req); const c=d.cohorts.find(x=>String(x.id)===String(req.params.cohortId)); if(!c){res.status(404); return res.type('html').send(html('Cohort Not Found','<h1>Cohort Not Found</h1><p>This cohort is not available to your account.</p>'));} res.type('html').send(html('Add Participant', addParticipantPage(c)));}));
